import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"燃木刀法","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/武学基础/燃木刀法.md","filePath":"4.资源分区/6.技艺及称号/武技类/武学基础/燃木刀法.md"}'),d={name:"4.资源分区/6.技艺及称号/武技类/武学基础/燃木刀法.md"};function l(_,a,i,p,c,b){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"燃木刀法",tabindex:"-1"},[s("燃木刀法 "),e("a",{class:"header-anchor",href:"#燃木刀法","aria-label":'Permalink to "燃木刀法"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风021")])])],-1),o('<h1 id="燃木刀法-1" tabindex="-1">燃木刀法 <a class="header-anchor" href="#燃木刀法-1" aria-label="Permalink to &quot;燃木刀法&quot;">​</a></h1><p>燃木刀法<br> C+1000<br> 前置：武学基础-战技入门<br> 注：此技艺遵循【武学总纲】<br> 少林七十二绝技之一，练成后在一根干木旁快劈九九八十一刀，刀刃不损木材丝毫，刀上发出的热力却可将木材点燃生火，故得此名。<br> 习得此刀法，可在使用任意刀法进行攻击时消耗两点内力，在画面表现上可以瞬息间连劈敌人九九八十一刀，不过最开始只能劈出两刀使本次攻击获得两点技艺加值以及一点高速。</p><p>此后，基于武学总纲，当此武学精熟程度达到以下程度时，将额外获得：<br> *初窥门径：五点高速，两点技艺加值。在画面表现上 你现在可以连劈九刀。<br> *渐入佳境：本次攻击升级为【连射】，增加一点附加成功和两点技艺加值，本次攻击中你的力量临时上升1点。在画面表现上，你现在可以连劈二十七刀。<br> *开宗立派：本次攻击附带一点不可豁免的燃烧不良点数，可叠加，并且可以攻击接触距离内的两个目标。在画面表现上，你现在可以连劈四十五刀。<br> *武道传奇：本次攻击再增加五点高速以及一点技艺加值。在画面表现上，你神功大成，可以连劈九九八十一刀。</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',5)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
